package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.SP;
import java.io.Closeable;
import java.io.Flushable;
import java.sql.ResultSet;
import java.sql.SQLException;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
    }

    private void doNothingOnPrivatePrint(CSVPrinter spyPrinter) throws Exception {
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        // Use Mockito to stub the private method via reflection proxy
        doAnswer(invocation -> null).when(spyPrinter, printMethod).invoke(any(), any(), anyInt(), anyInt());
    }

    private void doNothingOnPrivatePrintViaReflection(CSVPrinter spyPrinter) throws Exception {
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        // No direct Mockito stubbing, so we will spy on public print and verify private print via reflection
    }

    private void verifyPrivatePrintCalled(CSVPrinter spyPrinter, Object arg1, CharSequence arg2, int arg3, int arg4) throws Exception {
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        // We cannot use verify(spyPrinter).print(...) because print is private.
        // Instead, we verify indirectly by spying on the public print method or by other means.
        // Here we will invoke the private method reflectively and check that it was called is not possible,
        // so we skip verify on private method and only verify public behavior or format calls.
    }

    @Test
    void testPrint_nullValue_nullStringNull() throws Exception {
        when(format.getNullString()).thenReturn(null);

        printer = new CSVPrinter(out, format);

        CSVPrinter spyPrinter = Mockito.spy(printer);

        // Instead of stubbing private method, just call the public print method
        spyPrinter.print(null);

        verify(format).getNullString();
        // Cannot verify private print call, so verify public behavior only
    }

    @Test
    void testPrint_nullValue_nullStringNotNull() throws Exception {
        when(format.getNullString()).thenReturn("NULL");

        printer = new CSVPrinter(out, format);

        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.print(null);

        verify(format).getNullString();
    }

    @Test
    void testPrint_nonNullValue() throws Exception {
        when(format.getNullString()).thenReturn(null);

        printer = new CSVPrinter(out, format);

        CSVPrinter spyPrinter = Mockito.spy(printer);

        String testValue = "value123";

        spyPrinter.print(testValue);

        verify(format, never()).getNullString();
    }
}
